<style>
  .stripes {
    transform: rotate(-30deg);
    transform-origin: center;
  }

  /* Yellow stripe defaults to filling the whole mask. On hover it shrinks to
     its natural band, revealing the other rainbow stripes underneath. On
     mouse-out the default rule re-applies and yellow transitions back up to
     fill the mask. */
  .stripe-yellow {
    transform-box: fill-box;
    transform-origin: center;
    transform: scale(8);
    transition: transform 700ms cubic-bezier(0.4, 0, 0.2, 1);
  }

  svg:hover .stripe-yellow {
    transform: scale(1);
  }

  @media (prefers-reduced-motion: reduce) {
    .stripe-yellow {
      transition: none;
    }
  }
</style>
